// src/components/LeetcodeLeaderboard.js
import React, { useEffect, useState } from 'react';
import './Leaderboard.css';

const LeetcodeLeaderboard = () => {
  const [leaderboard, setLeaderboard] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetch('http://localhost:5001/api/leetcode')
      .then((response) => {
        if (!response.ok) {
          throw new Error('Failed to fetch Leetcode leaderboard data');
        }
        return response.json();
      })
      .then((data) => {
        // Inspect the returned data to determine its structure.
        console.log('Leetcode API response:', data);
        let leaderboardArray = [];

        // Example 1: If the API returns an object with a "leaderboard" property:
        if (data.leaderboard && Array.isArray(data.leaderboard)) {
          leaderboardArray = data.leaderboard;
        }
        // Example 2: If the API returns the array directly:
        else if (Array.isArray(data)) {
          leaderboardArray = data;
        } else {
          // If the format is unexpected, you can throw an error or use a fallback.
          console.error('Unexpected Leetcode API format:', data);
        }

        setLeaderboard(leaderboardArray);
        setLoading(false);
      })
      .catch((err) => {
        console.error('Error fetching Leetcode leaderboard:', err);
        setError(err.message);
        setLoading(false);
      });
  }, []);

  if (loading) {
    return (
      <div className="loading">
        <p>Loading Leetcode data...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="error">
        <p>{error}</p>
      </div>
    );
  }

  return (
    <div className="leaderboard-container">
      <h1 className="leaderboard-header">Leetcode Leaderboard</h1>
      <div className="table-responsive">
        <table className="leaderboard-table">
          <thead>
            <tr>
              <th>Username</th>
              <th>Ranking</th>
              <th>Total Solved</th>
              <th>Acceptance Rate</th>
            </tr>
          </thead>
          <tbody>
            {leaderboard.map((user, index) => (
              <tr key={index}>
                <td>{user.username}</td>
                <td>{user.ranking || 'N/A'}</td>
                <td>{user.totalSolved || 'N/A'}</td>
                <td>{user.acceptanceRate ? user.acceptanceRate + '%' : 'N/A'}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default LeetcodeLeaderboard;
